import ExampleItem from "./ExampleItem";
import SpeakBtn from "./SpeakBtn";
import Synonyms from "./Synonyms";

const VerbCard = ({ verb, onSelect }) => {
  return (
    <div className="w-full bg-[#221f35] border border-gray-700 rounded-xl p-4 shadow-sm hover:shadow-md transition">
      <div className="flex flex-col lg:flex-row gap-3">
        {/* Verb Info */}
        <div className="w-full lg:w-4/12 text-gray-900 dark:text-gray-100">
          <div className="flex flex-col sm:flex-row sm:items-start gap-3">
            {/* Speak */}
            <div className="flex items-center gap-3 border border-white/10 rounded-lg w-fit">
              <SpeakBtn text={verb?.base} className="p-2" />
            </div>

            {/* Verb Info */}
            <div className="flex flex-col w-full">
              <div className="flex items-start gap-2 px-3 py-1 border border-white/10 rounded-lg w-full sm:w-fit">
                <div className="flex flex-col items-center">
                  <span className="text-lg sm:text-xl font-bold text-gray-200">
                    {verb?.base}
                  </span>
                  <div className="text-xs sm:text-sm">
                    /<span className="text-[#eb0a0a]">{verb?.phonetic}</span>/
                  </div>
                </div>

                <span className="text-gray-400 text-sm sm:text-base">
                  {verb?.meaning}
                </span>
              </div>
            </div>
          </div>

          {/* V2 V3 */}
          <div className="flex flex-wrap gap-2 text-xs sm:text-sm mt-2">
            {verb?.v2 && (
              <span className="px-2 py-1 border text-[#e8c547] border-white/10 rounded-md">
                {verb?.v2}
              </span>
            )}
            {verb?.v3 && (
              <span className="px-2 py-1 border text-[#24fd0c] border-white/10 rounded-md">
                {verb?.v3}
              </span>
            )}
          </div>
        </div>

        {/* Examples */}
        <div className="w-full lg:w-7/12 space-y-1">
          {verb?.examples?.map((ex, i) => (
            <ExampleItem key={i} ex={ex} />
          ))}
        </div>

        {/* more examples button */}
        <div className="w-full lg:w-1/12">
          <button
            onClick={() => onSelect(verb)}
            className=" w-full sm:w-auto p-1 bg-[#e8c547] text-black font-medium rounded-lg hover:bg-[#f2d46b] transition text-sm cursor-pointer"
          >
            See More
          </button>
        </div>
      </div>
      {/* synonyms added in here future if time allows now jsut formate design */}
      {verb?.synonyms && (
        <div className=" flex items-center justify-start gap-2 border-gray-700 pt-3">
          <p className="text-white font-bold">Synonyms:</p>
          <Synonyms synonyms={verb.synonyms} />
        </div>
      )}
    </div>
  );
};

export default VerbCard;
